gastos = [4.50, 4.50, 12.00, 4.50, 25.00]

for valor in gastos:
    if valor > 10.00:
        print("Gasto alto detectado:", valor)

valores = [12, -3, 18, 7, -1]
qtd_dias_negativos = 0

for v in valores:
    if v < 0:
        qtd_dias_negativos += 1

print("Dias no vermelho:", qtd_dias_negativos)  # 2

valores = [12, -3, 18, 7, -1]
soma_positivos = 0

for v in valores:
    if v >= 0:
        soma_positivos += v

print("Total positivo:", soma_positivos)  # 37

horas_semana = [8, 9, 7, 10, 6, 12, 0]
dias_com_extra = 0

for horas in horas_semana:
    if horas > 8:
        dias_com_extra += 1

print("Dias com horas extras:", dias_com_extra)

horas_semana = [8, 9, 7, 10, 6, 12, 0]
total_extras = 0

for horas in horas_semana:
    if horas > 8:
        total_extras += (horas - 8)

print("Total de horas extras:", total_extras)
